const data = $input.all();

for (const item of data) {
  // O comando "Reflect" força a deleção sem o editor reclamar de Tipos
  Reflect.deleteProperty(item, 'binary');
}

return data;

// 1. Acessa os dados de entrada
const firstItem = (typeof items !== 'undefined' && items.length > 0) ? items[0] : $input.first();

// 2. Extrai e faz o PARSE do texto JSON
let inputData = [];

if (firstItem.json.concatenated_data) {
    try {
        // Transformamos o texto "[{...}]" em um Array real via JSON.parse
        inputData = JSON.parse(firstItem.json.concatenated_data);
    } catch (e) {
        // Se falhar o parse, tenta usar o json direto caso já seja objeto
        inputData = firstItem.json.data || [];
    }
} else if (Array.isArray(firstItem.json)) {
    inputData = firstItem.json;
} else if (firstItem.json.data) {
    inputData = firstItem.json.data;
}

// Se o inputData não for uma lista (array), forçamos ser uma lista vazia para não quebrar o loop
if (!Array.isArray(inputData)) {
    inputData = []; 
}

// --- INÍCIO DO PROCESSAMENTO ---

const cleanData = [];

for (const row of inputData) {
  // Garante que row é um objeto válido
  if (typeof row !== 'object' || row === null) continue;

  const cleanItem = {};
  let textForRag = ""; 

  // Como os dados já têm as chaves corretas (ex: "Empresa", "CNPJ"), 
  // iteramos direto sobre elas
  for (const key in row) {
    const value = row[key];

    // Verifica se o valor não é nulo, indefinido ou vazio
    if (value !== undefined && value !== null && value !== '') {
      cleanItem[key] = value;
      // Monta o texto para o RAG dinamicamente
      textForRag += `${key}: ${value}. `;
    }
  }

  // Se o objeto não estiver vazio, adiciona a propriedade de texto e insere no array final
  if (Object.keys(cleanItem).length > 0) {
    cleanItem.text_for_rag = textForRag.trim();
    cleanData.push({ json: cleanItem });
  }
}

return cleanData;

// Limpeza de Docs - lida com saídas dos nós Extract PDF Text (campo "text")
// e Extract Document Text (campo "data"). Detecta PDFs sem camada de texto
// (ex.: digitalizações geradas por PDFCreator) e sinaliza claramente.

const out = [];

for (const item of $input.all()) {
  // 1. Descobre onde está o conteúdo bruto
  const sourceField = item.json.text != null ? 'text'
                    : item.json.data != null ? 'data'
                    : null;

  if (!sourceField) {
    // Nada para limpar — repassa como veio
    out.push(item);
    continue;
  }

  const raw = String(item.json[sourceField] ?? '');

  // 2. Remove TUDO que não é letra, número, pontuação, espaço ou quebra de linha
  //    (mata binários que vazam de PDFs problemáticos)
  let cleanText = raw.replace(/[^\p{L}\p{N}\p{P}\p{Z}\n]/gu, '');

  // 3. Remove sequências de escape Unicode incompletas
  cleanText = cleanText.replace(/\\u/g, '');

  // 4. Normaliza espaços/quebras de linha excessivas para medir conteúdo real
  const meaningful = cleanText.replace(/\s+/g, '').trim();

  // 5. Detecta PDF sem texto extraível (apenas \n\n\n... do pdf-parse).
  //    Esses arquivos quase sempre são digitalizações/imagens dentro do PDF
  //    e precisam de OCR para serem indexados.
  if (meaningful.length < 20) {
    const fileTitle = $('Set File ID - to Context')?.first()?.json?.file_title ?? '(desconhecido)';
    const fileId    = $('Set File ID - to Context')?.first()?.json?.file_id    ?? '(sem id)';
    const ocrUsed   = item.json.ocr_used === true;
    throw new Error(
      `PDF sem texto utilizavel: "${fileTitle}" (file_id=${fileId}). ` +
      (ocrUsed
        ? `OCR via Azure OpenAI tambem nao retornou texto. Verifique se o deployment tem suporte a visao/PDF e se o arquivo nao esta protegido/corrompido.`
        : `O arquivo provavelmente e uma digitalizacao/imagem sem camada de texto e o branch OCR nao foi acionado.`)
    );
  }

  // 6. Limite de segurança (50k chars) e grava no MESMO campo de origem,
  //    além de em "data" para compatibilidade com o Default Data Loader.
  const finalText = cleanText.substring(0, 50000);
  item.json[sourceField] = finalText;
  item.json.data = finalText;

  out.push(item);
}

return out;

// Anexa category_id/category_code do contexto da categoria pai
// (Get Categories with Folders) a cada arquivo retornado pelo listing do Drive.
// Usado no fluxo de RESET (reprocessamento de todas as pastas).
const cat = $('Get Categories with Folders').item.json || {};
return $input.all().map(i => ({
  json: {
    ...i.json,
    category_id: cat.id || null,
    category_code: cat.code || null,
    session_id: null
  }
}));

// Anexa metadata do body do webhook (InsertFile-drive) ao arquivo recém-uploaded.
// Usado no fluxo de UPLOAD via CHAT (com session_id).
const body = ($('InsertFile-drive').first().json.body) || {};
return $input.all().map(i => ({
  json: {
    ...i.json,
    category_id: body.category_id || null,
    category_code: body.category_code || null,
    session_id: body.sessionId || body.session_id || null
  }
}));

// Extrai 'categoria' (code) do body multipart e filename do binário.
const item = $input.first();
const body = item.json.body || item.json || {};
const categoria = String(body.categoria || body.category_code || '').trim();
if (!categoria) throw new Error('Campo "categoria" (category_code) é obrigatório.');

const bin = item.binary && (item.binary.data || item.binary[Object.keys(item.binary)[0]]);
if (!bin) throw new Error('Arquivo "data" não enviado no multipart.');

const filename = bin.fileName || body.filename || '';
if (!filename) throw new Error('Não foi possível determinar o nome do arquivo.');

item.json = {
  ...item.json,
  categoria,
  filename,
  mime_type: bin.mimeType || 'application/octet-stream'
};
return item;

const webhook = $('Parse Upload Payload').first().json;
const cat = $input.first().json;
if (!cat || !cat.category_id) throw new Error('Categoria não encontrada: ' + webhook.categoria);
if (!cat.drive_folder_id || String(cat.drive_folder_id).trim() === '') {
  throw new Error('Categoria ' + webhook.categoria + ' não possui drive_folder_id configurado.');
}
return [{
  json: {
    categoria: webhook.categoria,
    filename: webhook.filename,
    mime_type: webhook.mime_type,
    category_id: cat.category_id,
    category_code: cat.category_code,
    category_name: cat.category_name,
    drive_folder_id: cat.drive_folder_id
  },
  binary: $('Webhook RAG Upload').first().binary
}];

const ctx = $('Build Upload Context').first().json;
const hits = $input.all().map(i => i.json).filter(f => f && f.id && f.name && !f.trashed);
const exact = hits.find(f => f.name === ctx.filename);
const binary = $('Build Upload Context').first().binary;
return [{
  json: {
    ...ctx,
    existing_file_id: exact ? exact.id : null,
    existing_web_view_link: exact ? (exact.webViewLink || null) : null,
    action: exact ? 'replace' : 'create'
  },
  binary
}];

// Normaliza o resultado do Drive (update OU upload) para o shape esperado
// pelo Loop Over Items / Set File ID - to Context.
const drive = $input.first().json || {};
const ctx = $('Decide Replace or Create').first().json;
const fileId = drive.id || ctx.existing_file_id;
if (!fileId) throw new Error('Drive não retornou file_id após upload/update.');
const dot = ctx.filename.lastIndexOf('.');
const code = dot > 0 ? ctx.filename.substring(0, dot) : ctx.filename;
return [{
  json: {
    id: fileId,
    name: ctx.filename,
    mimeType: drive.mimeType || ctx.mime_type,
    webViewLink: drive.webViewLink || ctx.existing_web_view_link || null,
    category_id: ctx.category_id,
    category_code: ctx.category_code,
    code,
    session_id: null
  }
}];

// Normaliza body: aceita { file_id } | { file_ids: [...] } | { ids: [...] }.
const b = ($input.first().json.body) || $input.first().json || {};
let ids = [];
if (Array.isArray(b.file_ids)) ids = b.file_ids;
else if (Array.isArray(b.ids)) ids = b.ids;
else if (b.file_id) ids = [b.file_id];
else if (b.id) ids = [b.id];
ids = ids.map(x => String(x || '').trim()).filter(Boolean);
if (ids.length === 0) throw new Error('file_id ou file_ids obrigatório.');
return [{ json: { ids, ids_csv: ids.map(s => s.replace(/[^a-zA-Z0-9_\-\.]/g, '')).join(',') } }];

// Garante session_id null e mantém o shape esperado pelo Loop Over Items.
const rows = $input.all();
if (rows.length === 0) throw new Error('Nenhum documento encontrado para os file_ids fornecidos.');
return rows.map(r => ({
  json: {
    id: r.json.id,
    name: r.json.name,
    mimeType: r.json.mimeType,
    webViewLink: r.json.webViewLink,
    category_id: r.json.category_id,
    category_code: r.json.category_code,
    code: r.json.code,
    session_id: null
  }
}));
